import{_ as t,o as e,c as r,a2 as o}from"./chunks/framework.Crpw6aS5.js";const c=JSON.parse('{"title":"1959年致合伙人信","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1959年/翻译.md","filePath":"01_letters/1959年/翻译.md"}'),p={name:"01_letters/1959年/翻译.md"};function n(i,a,_,l,s,d){return e(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="_1959年致合伙人信" tabindex="-1">1959年致合伙人信 <a class="header-anchor" href="#_1959年致合伙人信" aria-label="Permalink to &quot;1959年致合伙人信&quot;">​</a></h1><p>沃伦·E·巴菲特 内布拉斯加州奥马哈市安德伍德大道5202号</p><h2 id="_1959年股市概况" tabindex="-1">1959年股市概况 <a class="header-anchor" href="#_1959年股市概况" aria-label="Permalink to &quot;1959年股市概况&quot;">​</a></h2><p>道琼斯工业平均指数无疑是使用最广泛的股票市场行为指标，在1959年呈现出一个有些问题的画面。该指数从583上涨到679，全年涨幅16.4%。加上持有该指数本来能收到的股息，1959年的整体收益为19.9%。</p><p>尽管这一数据显示市场强劲，但纽约证券交易所全年下跌的股票多于上涨的股票，以710比628的优势胜出。道琼斯铁路平均指数和公用事业平均指数均出现下跌。</p><p>大多数投资信托公司相比工业平均指数表现艰难。Tri-Continental公司——全国最大的封闭式投资公司（总资产4亿美元）——全年整体收益约为5.7%。该公司总裁弗雷德·布朗在近日对分析师协会的演讲中这样评价1959年的市场：</p><p>&quot;但是，尽管我们喜欢投资组合，Tri-Continental持仓在1959年的市场表现令我们失望。投资者情绪和热情发挥如此大作用的市场，比如1959年的市场，对于注重价值并致力于长期投资的投资经理来说很难适应。也许我们还没有调整好我们的太空靴。然而，我们认为，像Tri-Continental这样的投资机构用股东的钱承担风险是有限度的，我们相信投资组合已经为来年做好了准备。&quot;</p><p>马萨诸塞州投资者信托公司——全国最大的共同基金，资产15亿美元——全年整体收益约为9%。</p><p>大多数人都知道，几年来我一直对整体股票市场水平非常担忧。迄今为止，这种谨慎是不必要的。按照以往的标准，目前&quot;蓝筹股&quot;股价包含相当大的投机成分，相应地存在损失的风险。也许其他估值标准正在演变，可能永久取代旧标准。我不这么认为。我很可能是错的；然而，我宁愿承受过度保守的惩罚，也不愿因采用&quot;新时代&quot;理念（树真的会长到天上）而面对错误的后果，可能是永久性的资本损失。</p><h2 id="_1959年业绩" tabindex="-1">1959年业绩 <a class="header-anchor" href="#_1959年业绩" aria-label="Permalink to &quot;1959年业绩&quot;">​</a></h2><p>在之前的信中，我们强调了一个建议的业绩标准，即在下跌或平稳时期表现相对较好（与整体市场指数和领先投资信托相比），但在快速上涨的市场中表现相对一般。</p><p>我们在1959年幸运地取得了相当不错的业绩。全年运营的六个合伙企业实现的整体净收益在22.3%到30%之间，平均约25.9%。这些合伙企业的投资组合现在约80%可比，但由于证券和现金在不同时间到位、向合伙人支付款项等原因，存在一些差异。过去几年，没有哪个合伙企业的业绩始终处于前列或末位，而且差异正在缩小，因为投资组合趋向于变得可比。</p><p>整体净收益是基于年初和年末的市场价值，并考虑了向合伙人支付或从他们那里收到的款项来确定的。它不是基于当年实际实现的利润，而是旨在衡量当年的清算价值变化。它是在允许合伙人利息（如果合伙协议中有规定）和任何分配给普通合伙人利润之前，但扣除运营费用之后。</p><p>主要运营费用是内布拉斯加州无形资产税，约为几乎所有证券市场价值的0.4%。去年是这项税收首次有效执行，当然使我们的业绩受到0.4%的惩罚。</p><h2 id="当前投资组合" tabindex="-1">当前投资组合 <a class="header-anchor" href="#当前投资组合" aria-label="Permalink to &quot;当前投资组合&quot;">​</a></h2><p>去年，我提到了一项新投资，占各合伙企业资产的约25%。目前这项投资约占资产的35%。这是一个异常大的比例，但有充分的理由。实际上，该公司部分是一家投资信托，拥有约三四十只其他高质量证券。我们的投资是基于其证券的市场价值和对营业业务的保守评估，以大幅低于资产价值的价格进行和入账。</p><p>我们是该公司最大的股东，差距很大，另外两个大股东同意我们的想法。在处置之前，这项投资的业绩将优于市场的可能性极高，我希望今年就能实现。</p><p>投资组合剩余的65%投资于我认为被低估的证券和workout业务。在可能的范围内，我继续尝试投资于至少部分与大盘走势无关的情形。</p><p>这一策略应该在熊市带来优异表现，在牛市带来平均水平。第一个预测可能在今年接受检验，因为在撰写本文时，道琼斯工业指数已经回撤了1959年涨幅的一半以上。</p><p>如果您有任何问题，或者我在任何方面表达不清楚，我非常乐意收到您的来信。</p><p>沃伦·E·巴菲特 1960年2月20日</p>',21)])])}const u=t(p,[["render",n]]);export{c as __pageData,u as default};
